import{_ as a,o,c as d,a3 as l}from"./chunks/framework.BTFg6ESq.js";const u=JSON.parse('{"title":"媒体生成参数面板诊断说明","description":"","frontmatter":{},"headers":[],"relativePath":"Plan/media-generator-parameter-diagnostics.md","filePath":"Plan/media-generator-parameter-diagnostics.md","lastUpdated":1781097236000}'),i={name:"Plan/media-generator-parameter-diagnostics.md"};function c(t,e,r,s,n,m){return o(),d("div",null,[...e[0]||(e[0]=[l('<h1 id="媒体生成参数面板诊断说明" tabindex="-1">媒体生成参数面板诊断说明 <a class="header-anchor" href="#媒体生成参数面板诊断说明" aria-label="Permalink to &quot;媒体生成参数面板诊断说明&quot;">​</a></h1><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>媒体生成参数面板现在只读取已添加模型对象上的 <code>mediaGenParams</code>，不再在运行态直接从全局模型元数据规则回退读取。若生成中心选中的 <code>profileId:modelId</code> 对应模型缺少 <code>mediaGenParams</code>，侧栏就会只剩基础区域和高级参数折叠区。</p><p>本诊断用于排查以下情况：</p><ul><li>生成中心选中的模型组合不是用户在模型编辑页查看的那个 profile 下的模型。</li><li>同一个 <code>modelId</code> 存在多个渠道，其中部分模型缺少 <code>mediaGenParams</code>。</li><li>重生成/分支复用了当前侧栏模型与参数，而不是原任务快照中的模型与参数。</li><li>历史 Remix 或会话配置写入了纯 <code>modelId</code>，导致 <code>profileId:modelId</code> 解析失败。</li></ul><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to &quot;使用方式&quot;">​</a></h2><ol><li>打开媒体生成工具。</li><li>保持异常界面和异常会话处于当前状态。</li><li>在右侧参数栏展开「高级参数」。</li><li>点击「导出诊断日志」。</li><li>将导出的 <code>media-generator-diagnostics-*.json</code> 发回。</li></ol><p>如果用户已经触发过“切换模型、重生成、切换分支”，也请在触发后立即导出一次。</p><h2 id="诊断文件关注点" tabindex="-1">诊断文件关注点 <a class="header-anchor" href="#诊断文件关注点" aria-label="Permalink to &quot;诊断文件关注点&quot;">​</a></h2><ul><li><p><code>comboInspection.active</code></p><ul><li>当前媒体类型的 <code>modelCombo</code>、解析出的 <code>profileId/modelId</code>、是否找到了 profile/model。</li><li><code>model.hasMediaGenParams</code> 表示当前实际选中模型对象是否有参数规则。</li><li><code>matchedMetadata.hasMediaGenParams</code> 表示全局元数据规则是否能匹配到参数规则。</li></ul></li><li><p><code>sameIdModels</code></p><ul><li>列出所有同 <code>modelId</code> 的模型实例。</li><li>如果其中一个有规则、另一个没规则，通常说明生成中心选中了另一个 profile 下的同名模型。</li></ul></li><li><p><code>currentConfig</code></p><ul><li>当前会话保存的各媒体类型模型组合与参数。</li><li>如果 <code>modelCombo</code> 不是 <code>profileId:modelId</code> 格式，参数面板可能无法解析模型。</li></ul></li><li><p><code>activeNode.metadata.taskSnapshot</code></p><ul><li>当前分支节点保存的任务快照。</li><li>可对比快照中的 <code>input.profileId/input.modelId/input.params</code> 与 <code>comboInspection.active</code>。</li></ul></li><li><p><code>recentLogs</code></p><ul><li>包含最近的 app 内存日志。</li><li>重点搜索： <ul><li><code>媒体生成参数面板模型状态</code></li><li><code>当前生成模型没有媒体生成参数规则</code></li><li><code>重生成参数解析完成</code></li><li><code>准备重生成媒体任务</code></li></ul></li></ul></li></ul><h2 id="预期判断" tabindex="-1">预期判断 <a class="header-anchor" href="#预期判断" aria-label="Permalink to &quot;预期判断&quot;">​</a></h2><p>若出现：</p><ul><li><code>matchedMetadata.hasMediaGenParams = true</code></li><li>但 <code>model.hasMediaGenParams = false</code></li></ul><p>说明全局 metadata 有规则，但当前已添加模型对象没有写入规则。此时同步/重置 metadata 不会自动修复该模型实例，需要应用模型预设或补充模型对象上的 <code>mediaGenParams</code>。</p><p>若出现：</p><ul><li><code>snapshotProfileId/snapshotModelId</code> 与 <code>currentProfileId/currentModelId</code> 不一致</li></ul><p>说明重生成时使用了当前侧栏模型，而不是源任务快照模型。这是重生成参数复用方向的重点修复点。</p><h2 id="_2026-06-10-样本结论" tabindex="-1">2026-06-10 样本结论 <a class="header-anchor" href="#_2026-06-10-样本结论" aria-label="Permalink to &quot;2026-06-10 样本结论&quot;">​</a></h2><p>样本 <code>media-generator-diagnostics-2026-06-10T12-04-03-244Z.json</code> 显示：</p><ul><li>当前 <code>modelCombo</code> 为 <code>llm-profile-1777482136893-hy95v90dj:gpt-image-2-hq</code>，profile 和 model 都能正常解析。</li><li>当前模型对象与全局 metadata 都存在 <code>mediaGenParams</code>，不是“元数据没有同步到模型”的情况。</li><li>当前 profile 类型为 <code>openai-compatible</code>，模型能力中启用了 <code>preferChat</code> 与 <code>iterativeRefinement</code>。</li><li>活跃任务错误为 <code>field messages is required</code>，说明重生成/恢复任务进入了 chat 分发路径但没有提供 <code>messages</code>。</li></ul><p>对应修复：</p><ul><li>重生成启动任务时传入当前消息路径。</li><li>对支持对话式生成的媒体任务，即使没有上下文消息，也兜底构造一条当前 prompt 的 user message。</li><li>参数规则默认填充同时写入 camelCase 与 snake_case 字段，避免 UI 读 <code>outputFormat/outputCompression/partialImages</code> 时拿不到由规则填充的默认值。</li></ul><h2 id="_2026-06-10-后续样本结论" tabindex="-1">2026-06-10 后续样本结论 <a class="header-anchor" href="#_2026-06-10-后续样本结论" aria-label="Permalink to &quot;2026-06-10 后续样本结论&quot;">​</a></h2><p>样本 <code>media-generator-diagnostics-2026-06-10T13-01-03-538Z.json</code> 显示：</p><ul><li><code>field messages is required</code> 已不再出现，说明 chat/preferChat 路径的 <code>messages</code> 兜底生效。</li><li>新的失败点变为 <code>响应中没有媒体资产</code>，说明上游请求完成，但 OpenAI 兼容 Chat adapter 没能把返回体里的图片抽取成 <code>response.images</code>。</li><li>任务状态出现 <code>completed</code> 但节点仍是 <code>generating</code> 的不一致，原因是“没有媒体资产”只写 warn 后继续把任务标记完成。</li></ul><p>对应修复：</p><ul><li>OpenAI 兼容 Chat adapter 从 <code>data/images/message.content/message.images</code> 等常见聊天响应形态中提取图片 URL 或 base64。</li><li>媒体生成响应没有任何图片/视频/音频时抛错，不再将任务标记为完成。</li></ul>',27)])])}const h=a(i,[["render",c]]);export{u as __pageData,h as default};
